mapper.sql:
from t1_v_dossier_instance_manage
deleted_at is null
and model_id = #{modelId}
and aircraft_id = #{aircraftId}
and tail_number like concat('%', #{tailNumber}, '%')
and instance_status = #{status}
and ( instance_code like concat('%', #{keyword}, '%') or instance_name like concat('%', #{keyword}, '%') or instance_label like concat('%', #{keyword}, '%') or tail_number like concat('%', #{keyword}, '%') or msn like concat('%', #{keyword}, '%') or template_name like concat('%', #{keyword}, '%') or generation_job_code like concat('%', #{keyword}, '%') )

mapper.select:
select


order by generate_time ${sortOrder}, updated_at ${sortOrder}, instance_code desc
limit #{offset}, #{pageSize}

select dci.id as characteristicId, dci.item_code as characteristicCode, dci.item_name as characteristicName, dci.lifecycle_stage as lifecycleStage, dci.aircraft_id as aircraftId, dci.bom_node_id as bomNodeId, dci.part_instance_id as partInstanceId, dci.is_key_part as isKeyPart, dci.source_system as sourceSystem, dci.source_table as sourceTable, dci.completeness_status as completenessStatus, dci.content_summary as contentSummary, cast(dci.attrs_json as char) as attrsJson, dci.created_at as createdAt, dci.updated_at as updatedAt from t1_dossier_instance di inner join t1_dossier_version dv on dv.id = di.current_version_id inner join t1_dossier_content_item dci on dci.dossier_version_id = dv.id where di.deleted_at is null and dci.item_status = 'active' and ( dci.is_key_part = 1 or dci.include_design_data = 1 or dci.include_manufacturing_data = 1 or dci.include_service_data = 1 )
and di.aircraft_id = #{productId}
and ( dci.item_code like concat('%', #{keyword}, '%') or dci.item_name like concat('%', #{keyword}, '%') or dci.content_summary like concat('%', #{keyword}, '%') )
order by dci.is_key_part desc, dci.lifecycle_stage, dci.sort_order, dci.item_code limit #{offset}, #{pageSize}

select dci.id as contentItemId, dci.dossier_instance_id as instanceId, dci.dossier_version_id as versionId, dci.structure_node_id as structureNodeId, dci.item_code as itemCode, dci.item_name as itemName, dci.item_type as itemType, dci.lifecycle_stage as lifecycleStage, dci.aircraft_id as aircraftId, dci.bom_node_id as bomNodeId, dci.part_instance_id as partInstanceId, dci.is_key_part as isKeyPart, dci.supply_mode as supplyMode, dci.source_system as sourceSystem, dci.source_table as sourceTable, dci.source_record_key as sourceRecordKey, dci.completeness_status as completenessStatus, dci.content_summary as contentSummary, dci.file_storage_key as fileStorageKey, cast(dci.source_trace_json as char) as sourceTraceJson, cast(dci.attrs_json as char) as attrsJson, dci.created_at as createdAt, dci.updated_at as updatedAt from t1_dossier_instance di inner join t1_dossier_version dv on dv.id = di.current_version_id inner join t1_dossier_content_item dci on dci.dossier_version_id = dv.id where di.deleted_at is null and dci.item_status = 'active'
and di.aircraft_id = #{productId}
and dci.bom_node_id = #{nodeId}
and dci.item_type = #{itemType}
and dci.lifecycle_stage = #{lifecycleStage}
and ( dci.item_code like concat('%', #{keyword}, '%') or dci.item_name like concat('%', #{keyword}, '%') or dci.content_summary like concat('%', #{keyword}, '%') or dci.source_record_key like concat('%', #{keyword}, '%') )
and ( dci.include_manufacturing_data = 1 or dci.lifecycle_stage = 'MANUFACTURING' or dci.item_type in ('PROCESS', 'ROUTE', 'AO', 'FO', 'WORK_ORDER', 'INSPECTION', 'TEST', 'QUALITY_CHECK', 'EQUIPMENT', 'RESOURCE') )
and ( dci.include_service_data = 1 or dci.lifecycle_stage = 'SERVICE' or dci.item_type in ('SERVICE', 'OPERATION', 'MAINTENANCE', 'REPAIR', 'FAULT', 'FAILURE', 'INSPECTION') )
order by dci.lifecycle_stage, dci.sort_order, dci.item_code limit #{offset}, #{pageSize}

select fr.id as documentEntryId, fr.dossier_instance_id as instanceId, fr.dossier_version_id as versionId, fr.structure_node_id as structureNodeId, sn.bom_node_id as bomNodeId, coalesce(fa.business_no, fr.target_code, fr.source_record_key) as docNo, coalesce(fa.business_title, fa.display_name) as title, coalesce(fa.storage_key, fa.storage_path, fa.access_url) as fileStorageKey, coalesce(fr.source_system, fa.source_system) as sourceSystem, coalesce(fr.source_table, fa.source_table) as sourceTable, coalesce(fr.source_record_key, fa.source_record_key) as sourceRecordKey, fr.relation_status as documentStatus, fr.completeness_status as completenessStatus, fr.required_flag as requiredFlag, fr.included_flag as includedFlag, cast(fr.source_trace_json as char) as sourceTraceJson, cast(fr.business_meta_json as char) as attrsJson from t1_dossier_instance di inner join t1_dossier_version dv on dv.id = di.current_version_id inner join t1_file_relation fr on fr.dossier_version_id = dv.id inner join t1_file_asset fa on fa.id = fr.file_id left join t1_dossier_structure_node sn on sn.id = fr.structure_node_id where di.deleted_at is null and fr.included_flag = 1 and fr.relation_status != 'deleted'
and di.aircraft_id = #{productId}
and sn.bom_node_id = #{nodeId}
and ( fa.business_no like concat('%', #{keyword}, '%') or fa.business_title like concat('%', #{keyword}, '%') or fa.display_name like concat('%', #{keyword}, '%') or fa.storage_key like concat('%', #{keyword}, '%') or fa.storage_path like concat('%', #{keyword}, '%') or fr.source_record_key like concat('%', #{keyword}, '%') )
and ( fa.business_type like concat('%', #{fileType}, '%') or fa.file_ext like concat('%', #{fileType}, '%') or fa.mime_type like concat('%', #{fileType}, '%') or fr.relation_type like concat('%', #{fileType}, '%') )
order by fr.required_flag desc, title, docNo limit #{offset}, #{pageSize}

mapper.sql:
from t1_dossier_operation_log dol


        and dol.dossier_instance_id = #{instanceId}


        and dol.business_subject_type = #{subjectType}


        and dol.operated_at >= #{beginTime}


        and dol.operated_at <= #{endTime}


        and (
            dol.operation_name like concat('%', #{keyword}, '%')
            or dol.result_message like concat('%', #{keyword}, '%')
            or dol.business_subject_id like concat('%', #{keyword}, '%')
        )

from t1_dossier_operation_log dol


        and dol.dossier_instance_id = #{instanceId}


        and dol.operation_type = #{operationType}


        and dol.operator_name like concat('%', #{operatorName}, '%')


        and dol.operated_at >= #{beginTime}


        and dol.operated_at <= #{endTime}


        and (
            dol.operation_name like concat('%', #{keyword}, '%')
            or dol.result_message like concat('%', #{keyword}, '%')
            or dol.business_subject_id like concat('%', #{keyword}, '%')
            or dol.operator_name like concat('%', #{keyword}, '%')
        )
